    "title": "Backlog column",
    "body": "Seeded cards look draggable and show priority, assignee, and due date metadata."
  },
  {
    "meta": "tRPC",
    "title": "Procedure status panel",
    "body": "Board queries and mutation names are listed so the API surface is visible."
  },
  {
    "meta": "Auth.js",
    "title": "Session area",
    "body": "Mock sign-in state shows how board ownership and member access will be enforced."
  },
  {
    "meta": "Turso",
    "title": "Database status",
    "body": "Turso/libSQL connection cards call out TURSO_URL and TURSO_ACCESS_TOKEN setup."
  },
  {
    "meta": "AUTH_SECRET",
    "title": "Environment checklist",
    "body": "AUTH_SECRET, GitHub OAuth, and database push reminders sit next to the preview."
  },
  {
    "meta": "realtime",
    "title": "Activity feed",
    "body": "Realtime activity explains card moves, comments, and sync events as the board changes."
  }
] as const;
const actions = [
  "Move kanban card",
  "Call tRPC mutation",
  "Check Turso status",
  "Review AUTH_SECRET"
] as const;

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">Bleeding-edge TypeScript kanban</p>
        <h1>Trellix tRPC Board</h1>
        <p className="lede">A runnable Trellix-style kanban board preview with draggable-looking task cards, tRPC procedure status, Auth.js session state, Turso/libSQL database health, realtime activity, and setup reminders for TURSO_URL, TURSO_ACCESS_TOKEN, and AUTH_SECRET.</p>
        <div className="metrics">
          {metrics.map((metric) => (
            <article key={metric.label} className="metric">
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
            </article>
          ))}
        </div>
      </section>


      <section className="grid">
        {cards.map((card) => (
          <article key={card.title} className="card">
            <span>{card.meta}</span>
            <h2>{card.title}</h2>
            <p>{card.body}</p>
          </article>
        ))}
      </section>

      <section className="actions">
        <h2>Action loop</h2>
        {actions.map((action) => <button key={action} type="button">{action}</button>)}
      </section>
    </main>
  );
}
